INSERT INTO public.profiles (user_id, full_name, email, age, bio, occupation, hobbies, budget, desired_location, move_in_date, accommodation_type, early_riser, night_owl, smoker, cleanliness_level, guest_preferences, ideal_flatmate, profile_completed, has_pets, wants_pets, show_budget, show_location, show_photos, show_habits, latitude, longitude)
VALUES
  ('a1111111-1111-1111-1111-111111111111', 'Maria Silva', 'maria.test@roompeer.com', 28, 'Friendly designer who loves cooking and weekend hikes. Looking for a clean, quiet flatmate.', 'Graphic Designer', ARRAY['Cooking', 'Hiking', 'Art', 'Yoga', 'Photography'], 3500, 'Budapest, HUN', '2026-04-15', 'apartment', true, false, false, 'clean', 'sometimes', 'Someone tidy, respectful, and who enjoys shared dinners occasionally.', true, false, true, true, true, true, true, 47.4979, 19.0402),
  ('a2222222-2222-2222-2222-222222222222', 'James Cooper', 'james.test@roompeer.com', 25, 'Software engineer and gamer. Night owl who keeps to myself but always up for a chat.', 'Software Engineer', ARRAY['Gaming', 'Technology', 'Music', 'Coffee', 'Movies'], 4500, 'Budapest, HUN', '2026-05-01', 'apartment', false, true, false, 'moderate', 'rarely', 'A chill flatmate who respects personal space but is friendly.', true, false, false, true, true, true, true, 47.5100, 19.0500),
  ('a3333333-3333-3333-3333-333333333333', 'Sophie Laurent', 'sophie.test@roompeer.com', 30, 'French expat, yoga instructor. Early bird and plant lover. Smoke-free home is a must!', 'Yoga Instructor', ARRAY['Yoga', 'Meditation', 'Cooking', 'Travel', 'Gardening'], 3000, 'Budapest, HUN', '2026-04-01', 'house', true, false, false, 'very-clean', 'sometimes', 'Looking for a health-conscious, tidy, and positive flatmate.', true, true, true, true, true, true, true, 47.4850, 19.0600),
  ('a4444444-4444-4444-4444-444444444444', 'Andrei Kovacs', 'andrei.test@roompeer.com', 35, 'Musician and teacher. I play guitar (with headphones!) and love exploring the city on weekends.', 'Music Teacher', ARRAY['Music', 'Travel', 'Sports', 'Reading', 'Dancing'], 4000, 'Budapest, HUN', '2026-06-01', 'apartment', false, false, false, 'moderate', 'often', 'Someone social and open-minded. Music lovers welcome!', true, false, false, true, true, true, true, 47.5200, 19.0300),
  ('a5555555-5555-5555-5555-555555555555', 'Elena Popescu', 'elena.test@roompeer.com', 26, 'Med student and fitness enthusiast. Clean freak who loves meal prepping and Netflix marathons.', 'Medical Student', ARRAY['Fitness', 'Cooking', 'Movies', 'Reading', 'Meditation'], 2800, 'Budapest, HUN', '2026-04-20', 'room', true, false, false, 'very-clean', 'rarely', 'Need a quiet, studious flatmate. Early risers preferred!', true, false, true, true, true, true, true, 47.4900, 19.0450);
